import java.util.*;

class Solution {
    public int[] findPermutation(String s) {
        int[] perm = new int[s.length() + 1];
        int left = 1;
        for(int i = 0; i < s.length(); i++) {
            if(s.charAt(i) == 'I') {
                perm[i] = left++;
                while(i + 1 < s.length() && s.charAt(i + 1) == 'D')
                    i++;
            }
        }
        perm[s.length()] = left++;
        for(int i = s.length() - 1; i >= 0; i--)
            if(s.charAt(i) == 'D')
                perm[i] = left++;
        return perm;
    }
}
```

